        let b = `https://www.pixiv.net/ajax/novel/${id}`,
            t = _ => Date.parse(new Date().toLocaleDateString()) + 828e5 - Date.now(),
            f = _ => cache.put(k, '1', Math.min(3600, t() / 1e3 | 0)) & java.ajax(b);
