@js:
(function() {
    // 模拟真实浏览器行为进行渲染
    var html = java.webView(result, "div.read-content:not(:empty)", null);
    var doc = org.jsoup.Jsoup.parse(html);
    var nodes = doc.select("div.read-content p");
    var res = [];

    for (var i = 0; i < nodes.size(); i++) {
        var text = nodes.get(i).text().trim();
        if (text.match(/加载中|正在获取|请稍候|继续滑动|爱丽丝书屋/) || text.length < 1) {
            continue;
        }
        res.push(text);
    }

    if (res.length === 0) {
        var backup = doc.select("div.read-content").text().trim();
        if (backup.length > 0 && !backup.includes("加载数据")) {
            return backup;
        }
    }
    return res.join("\n");
})();
